/// <summary>
/// check if journal can be posted or not
/// </summary>
/// <param name = "_sourceLineTable">Common _sourceLineTable</param>
/// <returns>boolean</returns>
[Hookable(false)]
protected boolean mayJournalTransBePosted(Common _sourceLineTable)
{
    boolean ret = next mayJournalTransBePosted(_sourceLineTable);

    if (ret && ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::Yes)
    {
        ret = this.ETGITMMayJournalTransBePosted(_sourceLineTable);
    }

    return ret;
}

/// <summary>
/// adding business logic to process outbound orders for landed cost
/// </summary>
/// <param name = "_sourceLineTable">Common _sourceLineTable</param>
/// <returns>boolean</returns>
internal boolean ETGITMMayJournalTransBePosted(Common _sourceLineTable)
{
    TableId lineListTableId = this.ITMFormLetterParmDataLineListTableId();
    boolean ret = true;

    if (lineListTableId == tableNum(ITMTable)
        || lineListTableId == tableNum(ITMContainers)
        || lineListTableId == tableNum(ITMFolioTable))
    {
        Query q = new Query();
        QueryBuildDataSource qbds = q.addDataSource(tableNum(ITMLine));
        qbds.addRange(fieldNum(ITMLine, RefTableId)).value(queryValue(_sourceLineTable.TableId));
        qbds.addRange(fieldNum(ITMLine, RefRecId)).value(queryValue(_sourceLineTable.RecId));

        ListEnumerator le = List::create(this.parmLineList()).getEnumerator();
        switch (lineListTableId)
        {
            case tableNum(ITMTable):
                ITMTable shipTable;
                while (le.moveNext())
                {
                    shipTable = le.current();
                    qbds.addRange(fieldNum(ITMLine, ShipId)).value(queryValue(shipTable.ShipId));
                }
                break;

            case tableNum(ITMContainers):
                ITMContainers shipContainers;
                while (le.moveNext())
                {
                    shipContainers = le.current();
                    qbds.addRange(fieldNum(ITMLine, ShipId)).value(
                        strfmt('((%1.%2=="%4")&&(%1.%3=="%5"))',
                            qbds.name(),
                            fieldStr(ITMLine, ShipId),
                            fieldStr(ITMLine, ShipContainerId),
                            queryValue(shipContainers.ShipId),
                            queryValue(shipContainers.ShipContainerId)));
                }
                break;

            case tableNum(ITMFolioTable):
                ITMFolioTable shipFolioTable;
                while (le.moveNext())
                {
                    shipFolioTable = le.current();
                    qbds.addRange(fieldNum(ITMLine, ShipFolioId)).value(queryValue(shipFolioTable.ShipFolioId));
                }
                break;
        }

        QueryRun qr = new QueryRun(q);
        ret = qr.next();
    }

    return ret;
}

[Hookable(false)]
public TableId ITMFormLetterParmDataLineListTableId()
{
    TableId tableId;

    if (this.parmLineList() != conNull())
    {
        ListEnumerator le = List::create(this.parmLineList()).getEnumerator();
        if (le.moveNext())
        {
            Common common = le.current();
            tableId = common.TableId;
        }
    }

    return tableId;
}

/// <summary>
/// adding business logic to process outbound orders for landed cost if this feature is enabled
/// </summary>
[Hookable(false)]
public void updateQueryBuild()
{
    next updateQueryBuild();

    if (ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::Yes)
    {
        TableId lineListTableId = this.ITMParmDataLineListTableId();

        if (lineListTableId == tableNum(ITMTable)
            || lineListTableId == tableNum(ITMContainers)
            || lineListTableId == tableNum(ITMFolioTable))
        {
            SysQueryRun chooseLines = this.parmQueryChooseLines();

            QueryBuildDataSource qbds = chooseLines.query().dataSourceTable(tableNum(SalesLine)).addDataSource(tableNum(ITMLine));

            qbds.relations(true);
            qbds.joinMode(JoinMode::ExistsJoin);
            qbds.fetchMode(QueryFetchMode::One2One);

            int selected = 0;

            qbds = chooseLines.query().dataSourceTable(tableNum(CustPackingSlipTrans));
            if (qbds)
            {
                qbds.fetchMode(QueryFetchMode::One2One);
            }

            ListEnumerator le = List::create(this.parmLineList()).getEnumerator();
            switch (lineListTableId)
            {
                case tableNum(ITMTable):
                    while (le.moveNext())
                    {
                        ITMTable shipTable = le.current();

                        selected++;
                        chooseLines.query().dataSourceTable(tableNum(ITMLine)).addRange(fieldNum(ITMLine, ShipId)).value(queryValue(shipTable.ShipId));
                    }
                    break;

                case tableNum(ITMContainers):
                    while (le.moveNext())
                    {
                        ITMContainers shipContainers = le.current();

                        selected++;
                        chooseLines.query().dataSourceTable(tableNum(ITMLine)).addRange(fieldNum(ITMLine, ShipId)).value(
                            strfmt('((%1.%2=="%4")&&(%1.%3=="%5"))',
                            chooseLines.query().dataSourceTable(tableNum(ITMLine)).name(),
                            fieldStr(ITMLine, ShipId),
                            fieldStr(ITMLine, ShipContainerId),
                            queryValue(shipContainers.ShipId),
                            queryValue(shipContainers.ShipContainerId)));
                    }
                    break;

                case tableNum(ITMFolioTable):
                    while (le.moveNext())
                    {
                        ITMFolioTable shipFolioTable = le.current();

                        selected++;
                        chooseLines.query().dataSourceTable(tableNum(ITMLine)).addRange(fieldNum(ITMLine, ShipFolioId)).value(queryValue(shipFolioTable.ShipFolioId));
                    }
                    break;
            }

            if (selected == 0)
            {
                chooseLines.query().dataSourceTable(tableNum(SalesTable)).enabled(false);
            }
        }
    }
}

private TableId ITMParmDataLineListTableId()
{
    TableId tableId;

    if (this.parmLineList() != conNull())
    {
        ListEnumerator le = List::create(this.parmLineList()).getEnumerator();
        if (le.moveNext())
        {
            Common common = le.current();
            tableId = common.TableId;
        }
    }

    return tableId;
}

